import {
  defineCollections,
  defineConfig,
  defineDocs,
} from "fumadocs-mdx/config";
import {
  BlogPostSchema,
  ChangelogEntrySchema,
  DocsPageSchema,
  LegalPageSchema,
} from "./src/lib/content-schemas";

export const { docs, meta } = defineDocs({
  dir: "src/content/docs",
  docs: { schema: DocsPageSchema },
});

export const { docs: apiDocs, meta: apiMeta } = defineDocs({
  dir: "src/content/api",
  docs: { schema: DocsPageSchema },
});

export const blogCollection = defineCollections({
  type: "doc",
  dir: "src/content/blog",
  schema: BlogPostSchema,
});

export const changelogCollection = defineCollections({
  type: "doc",
  dir: "src/content/changelog",
  schema: ChangelogEntrySchema,
});

export const legalCollection = defineCollections({
  type: "doc",
  dir: "src/content/legal",
  schema: LegalPageSchema,
});

export default defineConfig({
  mdxOptions: {
    // Disable fumadocs' built-in Shiki code highlighting
    // to preserve language-* className for custom SSRCodeBlock
    rehypeCodeOptions: false,
  },
});

import { z } from "zod";

const AuthorSchema = z.object({
  name: z.string().min(1),
  url: z.url(),
  twitterHandle: z.string().min(1),
  jobTitle: z.string().min(1).optional(),
});

const FaqItemSchema = z.object({
  question: z.string().min(10),
  answer: z.string().min(20),
});

const HowToStepSchema = z.object({
  name: z.string().min(1),
  text: z.string().min(20),
  url: z.url().optional(),
});

const BasePageSchema = z.object({
  title: z.string().min(1),
  description: z.string().min(50).max(160),
  keywords: z.array(z.string().min(1)).min(3).max(20),
  canonicalUrl: z.url(),
  ogTitle: z.string().min(1).max(70),
  ogDescription: z.string().min(50).max(160),
  noindex: z.boolean().default(false),
  nofollow: z.boolean().default(false),
});

const ContentPageSchema = BasePageSchema.extend({
  authors: z.array(AuthorSchema).min(1),
  publishedAt: z.iso.datetime(),
  updatedAt: z.iso.datetime(),
  faq: z.array(FaqItemSchema).min(1),
  featuredImage: z.string().startsWith("/images/").optional(),
});

export const BlogPostSchema = ContentPageSchema.extend({
  canonicalUrl: z
    .url()
    .refine((val) => val.startsWith("https://lightfast.ai/blog/"))
    .optional(),
  category: z.enum([
    "engineering",
    "product",
    "company",
    "tutorial",
    "research",
  ]),
  readingTimeMinutes: z.number().int().min(1),
  featured: z.boolean().default(false),
  tldr: z.string().min(20).max(300),
  howToSteps: z.array(HowToStepSchema).min(2).optional(),
});

export const ChangelogEntrySchema = ContentPageSchema.extend({
  canonicalUrl: z
    .url()
    .refine((val) => val.startsWith("https://lightfast.ai/changelog/"))
    .optional(),
  version: z.string().min(1),
  type: z.enum(["feature", "improvement", "fix", "breaking"]),
  tldr: z.string().min(20).max(300),
  improvements: z.array(z.string().min(1)).optional(),
});

export const LegalPageSchema = BasePageSchema.extend({
  canonicalUrl: z
    .url()
    .refine((val) => val.startsWith("https://lightfast.ai/legal/"))
    .optional(),
  updatedAt: z.iso.datetime(),
  effectiveAt: z.iso.datetime(),
});

export const DocsPageSchema = BasePageSchema.extend({
  canonicalUrl: z
    .url()
    .refine((val) => val.startsWith("https://lightfast.ai/docs/"))
    .optional(),
  authors: z.array(AuthorSchema).min(1),
  publishedAt: z.iso.datetime(),
  updatedAt: z.iso.datetime(),
  proficiencyLevel: z
    .enum(["Beginner", "Intermediate", "Advanced", "Expert"])
    .optional(),
});

// Inferred TypeScript types
export type BlogPostData = z.infer<typeof BlogPostSchema>;
export type ChangelogEntryData = z.infer<typeof ChangelogEntrySchema>;
export type LegalPageData = z.infer<typeof LegalPageSchema>;
export type DocsPageData = z.infer<typeof DocsPageSchema>;

// Fields required by the SEO layer — satisfied structurally by BlogPostData,
// ChangelogEntryData, and DocsPageData. Derived from BlogPostData so schema
// renames propagate here automatically.
export type ContentSeoData = Pick<
  BlogPostData,
  | "authors"
  | "description"
  | "keywords"
  | "nofollow"
  | "noindex"
  | "ogDescription"
  | "ogTitle"
  | "publishedAt"
  | "title"
  | "updatedAt"
>;

// Derived from Zod — Zod is the sole source of truth for these unions
export type BlogCategory = BlogPostData["category"];
// → "engineering" | "product" | "company" | "tutorial" | "research"

export type ChangelogType = ChangelogEntryData["type"];
// → "feature" | "improvement" | "fix" | "breaking"

/**
 * App navigation configuration
 *
 * Exposes nav groups using defineNavItems() for compile-time route validation:
 * - INTERNAL_NAV: links within the app/site
 * - SOCIAL_NAV: external/social links with optional icons
 */
import { defineNavItems } from "~/types/nav";

export const INTERNAL_NAV = defineNavItems([
  { title: "Pricing", href: "/pricing" },
  { title: "Early Access", href: "/early-access", microfrontend: true },
  { title: "Docs", href: "/docs/get-started/overview" },
]);

export const SOCIAL_NAV = defineNavItems([
  {
    title: "X",
    label: "X",
    href: "https://x.com/lightfastai",
    icon: "twitter",
    external: true,
  },
  {
    title: "GitHub",
    label: "GitHub",
    href: "https://github.com/lightfastai",
    icon: "gitHub",
    external: true,
  },
  {
    title: "Discord",
    label: "Discord",
    href: "#discord",
    icon: "discord",
    external: true,
  },
]);

// Resources sub-navigation used for the marketing header dropdown
export const RESOURCES_NAV = defineNavItems([
  { title: "Changelog", href: "/changelog" },
  { title: "Blog", href: "/blog" },
]);

// Navigation for the pitch-deck pages
export const PITCH_DECK_NAV = defineNavItems([
  { title: "Home", href: "/" },
  { title: "Pricing", href: "/pricing" },
  { title: "Blog", href: "/blog" },
  { title: "Changelog", href: "/changelog" },
  { title: "Docs", href: "/docs/get-started/overview" },
  { title: "Contact", href: "mailto:jp@lightfast.ai", external: true },
]);

import type { GraphContext } from "@vendor/seo/json-ld";
import type { Metadata } from "next";
import type { Crumb } from "./builders";
import {
  buildApiRefJsonLd,
  buildBlogPostJsonLd,
  buildChangelogEntryJsonLd,
  buildDocsJsonLd,
  buildLegalJsonLd,
} from "./builders";
import type {
  BlogPostData,
  ChangelogEntryData,
  ContentSeoData,
  DocsPageData,
  LegalPageData,
} from "./content-schemas";
import { createArticleMetadata, createMetadata } from "./content-seo";
import type {
  ApiRefUrl,
  BlogPostUrl,
  ChangelogUrl,
  DocsUrl,
  LegalUrl,
} from "./url-types";

interface SeoBundle {
  readonly jsonLd: GraphContext;
  readonly metadata: Metadata;
}

// SeoBundle owns canonical URL derivation — derives from the typed url param,
// respects frontmatter canonicalUrl as an escape hatch.
// Both metadata.alternates.canonical and JSON-LD url come from the same value:
// drift is structurally impossible.

function buildArticleMetadata(
  data: ContentSeoData,
  canonicalUrl: string,
  titleSuffix: string,
  siteName: string,
  ogImageUrl?: string
): Metadata {
  return createArticleMetadata(
    {
      title: `${data.title} – ${titleSuffix}`,
      description: data.description,
      keywords: data.keywords,
      authors: data.authors.map((a) => ({ name: a.name, url: a.url })),
      creator: "Lightfast",
      publisher: "Lightfast",
      robots: {
        index: !data.noindex,
        follow: !data.nofollow,
        googleBot: {
          index: !data.noindex,
          follow: !data.nofollow,
          "max-video-preview": -1,
          "max-image-preview": "large",
          "max-snippet": -1,
        },
      },
      alternates: { canonical: canonicalUrl },
      openGraph: {
        title: data.ogTitle,
        description: data.ogDescription,
        url: canonicalUrl,
        siteName,
        locale: "en_US",
        authors: data.authors.map((a) => a.url),
        ...(ogImageUrl && {
          images: [
            {
              url: ogImageUrl,
              width: 1200,
              height: 630,
              alt: data.ogTitle,
            },
          ],
        }),
      },
      twitter: {
        card: "summary_large_image",
        title: data.ogTitle,
        description: data.ogDescription,
        site: "@lightfastai",
        creator: "@lightfastai",
        ...(ogImageUrl && { images: [ogImageUrl] }),
      },
      category: "Technology",
    },
    { publishedAt: data.publishedAt, updatedAt: data.updatedAt }
  );
}

export function emitBlogPostSeo(
  data: BlogPostData,
  url: BlogPostUrl
): SeoBundle {
  const canonicalUrl = data.canonicalUrl ?? url;
  return {
    metadata: buildArticleMetadata(
      data,
      canonicalUrl,
      "Lightfast Blog",
      "Lightfast Blog"
    ),
    jsonLd: buildBlogPostJsonLd(data, url),
  };
}

export function emitChangelogEntrySeo(
  data: ChangelogEntryData,
  url: ChangelogUrl
): SeoBundle {
  const canonicalUrl = data.canonicalUrl ?? url;
  return {
    metadata: buildArticleMetadata(
      data,
      canonicalUrl,
      "Lightfast Changelog",
      "Lightfast Changelog"
    ),
    jsonLd: buildChangelogEntryJsonLd(data, url),
  };
}

export function emitDocsSeo(
  data: DocsPageData,
  url: DocsUrl,
  breadcrumbs: Crumb[]
): SeoBundle {
  const canonicalUrl = data.canonicalUrl ?? url;
  const ogImageUrl = url.replace("/docs/", "/docs/og/");
  return {
    metadata: buildArticleMetadata(
      data,
      canonicalUrl,
      "Lightfast Docs",
      "Lightfast Documentation",
      ogImageUrl
    ),
    jsonLd: buildDocsJsonLd(data, url, breadcrumbs),
  };
}

export function emitLegalSeo(data: LegalPageData, url: LegalUrl): SeoBundle {
  const canonicalUrl = data.canonicalUrl ?? url;
  return {
    metadata: createMetadata({
      title: `${data.title} – Lightfast`,
      description: data.description,
      keywords: data.keywords,
      creator: "Lightfast",
      publisher: "Lightfast",
      robots: {
        index: !data.noindex,
        follow: !data.nofollow,
        googleBot: {
          index: !data.noindex,
          follow: !data.nofollow,
          "max-video-preview": -1,
          "max-image-preview": "large",
          "max-snippet": -1,
        },
      },
      alternates: { canonical: canonicalUrl },
      openGraph: {
        title: data.ogTitle,
        description: data.ogDescription,
        type: "website",
        url: canonicalUrl,
        siteName: "Lightfast",
        locale: "en_US",
      },
      twitter: {
        card: "summary_large_image",
        title: data.ogTitle,
        description: data.ogDescription,
        site: "@lightfastai",
        creator: "@lightfastai",
      },
    }),
    jsonLd: buildLegalJsonLd(data, url),
  };
}

export function emitApiRefSeo(
  data: DocsPageData,
  url: ApiRefUrl,
  breadcrumbs: Crumb[]
): SeoBundle {
  const canonicalUrl = data.canonicalUrl ?? url;
  const ogImageUrl = url.replace(
    "/docs/api-reference/",
    "/docs/api-reference/og/"
  );
  return {
    metadata: buildArticleMetadata(
      data,
      canonicalUrl,
      "Lightfast API Reference",
      "Lightfast API Reference",
      ogImageUrl
    ),
    jsonLd: buildApiRefJsonLd(data, url, breadcrumbs),
  };
}

import type { BlogPosting, GraphContext } from "@vendor/seo/json-ld";
import type { ChangelogEntryData, ChangelogType } from "~/lib/content-schemas";
import type { ChangelogUrl } from "~/lib/url-types";
import {
  buildBreadcrumbList,
  buildFaqEntity,
  buildOrganizationEntity,
  buildWebSiteEntity,
} from "./shared";

// Exhaustive mapping — adding a new ChangelogType errors here until handled
const CHANGELOG_SECTIONS: Record<ChangelogType, string> = {
  feature: "Changelog / Feature",
  improvement: "Changelog / Improvement",
  fix: "Changelog / Fix",
  breaking: "Changelog / Breaking Change",
};

function buildChangelogEntryEntity(
  data: ChangelogEntryData,
  url: ChangelogUrl
): Omit<BlogPosting, "@id" | "url"> {
  return {
    "@type": "BlogPosting",
    headline: data.title,
    description: data.description,
    abstract: data.tldr,
    datePublished: data.publishedAt,
    dateModified: data.updatedAt,
    author: data.authors.map((a) => ({
      "@type": "Person" as const,
      name: a.name,
      url: a.url,
      ...(a.jobTitle ? { jobTitle: a.jobTitle } : {}),
      sameAs: [`https://x.com/${a.twitterHandle.replace(/^@/, "")}`],
    })),
    image: {
      "@type": "ImageObject" as const,
      url: `${url}/opengraph-image`,
      width: "1200",
      height: "630",
    },
    keywords: [...data.keywords, data.version, data.type].join(", "),
    articleSection: CHANGELOG_SECTIONS[data.type],
    inLanguage: "en-US",
    isPartOf: { "@id": "https://lightfast.ai/#website" },
    publisher: { "@id": "https://lightfast.ai/#organization" },
  };
}

export function buildChangelogEntryJsonLd(
  data: ChangelogEntryData,
  url: ChangelogUrl
): GraphContext {
  const entity = buildChangelogEntryEntity(data, url);
  return {
    "@context": "https://schema.org",
    "@graph": [
      buildOrganizationEntity(),
      buildWebSiteEntity(),
      { ...entity, "@id": `${url}#article`, url },
      ...(data.faq.length > 0 ? [buildFaqEntity(data.faq, url)] : []),
      buildBreadcrumbList([
        { name: "Home", url: "https://lightfast.ai" },
        { name: "Changelog", url: "https://lightfast.ai/changelog" },
        { name: data.title, url },
      ]),
    ],
  };
}

