import type { IntegrationPageData } from "./content-schemas";
import type { IntegrationUrl } from "./url-types";
import { buildIntegrationJsonLd } from "./builders";

export function emitIntegrationSeo(
  data: IntegrationPageData,
  url: IntegrationUrl
